void GEN_BIT::operator()() {
    if (CLK && !RST) {
        RUN = (REP == 0) || (RX <= REP);
        if (RUN) {
            if (CNT == STEPS) {
                CNT = 0;
            }
            if (CNT == 0) {
                R0 = IN0;
                R1 = IN1;
                R2 = IN2;
                R3 = IN3;
            }
            if ((CNT < STEPS)) {
                Q0 = ((static_cast<uint64_t>(R0) >> 0) & 1);
                Q1 = ((static_cast<uint64_t>(R1) >> 0) & 1);
                Q2 = ((static_cast<uint64_t>(R2) >> 0) & 1);
                Q3 = ((static_cast<uint64_t>(R3) >> 0) & 1);
                R0 = SHR(R0, 1);
                R1 = SHR(R1, 1);
                R2 = SHR(R2, 1);
                R3 = SHR(R3, 1);
            }
            CNT = CNT + 1;
            if ((CNT == STEPS) && (REP != 0)) {
                RX = RX + 1;
            }
            if ((RX > REP) && (REP != 0)) {
                RUN = false;
            }
        }
    } else {
        if (RST) {
            RUN = false;
            Q0 = false;
            Q1 = false;
            Q2 = false;
            Q3 = false;
            R0 = 0;
            R1 = 0;
            R2 = 0;
            R3 = 0;
            CNT = 0;
            RX = 1;
        }
    }
}

