GEN_SQR::GEN_SQR() {
    // Initialize variables
}

void GEN_SQR::operator()() {
    if (DC == 0.0) {
        OUT = -AM * 0.5 + OS;
        Q = false;
        return;
    } else if (DC == 1.0) {
        OUT = AM * 0.5 + OS;
        Q = true;
        return;
    }
    TX = TO_TIME(T_PLC_MS()) - LAST;
    DL = MODR(DL, 1.0);
    if (DL < 0.0) {
        DL = 1.0 - DL;
    }
    DC = MODR(DC, 1.0);
    if (DC < 0.0) {
        DC = 1.0 - DC;
    }
    if (!INIT) {
        INIT = true;
        LAST = TX;
        TX = 0LL;
    }
    if (TX >= PT) {
        LAST = LAST + PT;
        TX = TX - PT;
    }
    if (MULTIME(PT, DL + DC) >= PT) {
        if (TX >= MULTIME(PT, DL + DC - 1)) {
            OUT = -AM * 0.5 + OS;
            Q = false;
        }
        if (TX >= MULTIME(PT, DL)) {
            OUT = AM * 0.5 + OS;
            Q = true;
        }
    } else {
        if (TX >= MULTIME(PT, DL)) {
            OUT = AM * 0.5 + OS;
            Q = true;
        }
        if (TX >= MULTIME(PT, DL + DC)) {
            OUT = -AM * 0.5 + OS;
            Q = false;
        }
    }
}

HOLIDAY::HOLIDAY() {
    // Initialize variables
}

void HOLIDAY::operator()() {
    if (LAST_ACTIVE == DATE_IN) {
        return;
    }
    LAST_ACTIVE = DATE_IN;
    if (LANGU == 0) {
        LX = LANGUAGE.DEFAULT;
    } else {
        LX = MIN(LANGUAGE.LMAX, LANGU);
    }
    JAHR = YEAR_OF_DATE(DATE_IN);
    OSTERN = EASTER(JAHR);
    WDX = DAY_OF_WEEK(DATE_IN);
    Y = false;
    for (I = 0; I <= SIZE; I++) {
        X_DATE = SET_DATE(JAHR, static_cast<IEC_INT>(HOLIDAYS[I].MONTH), static_cast<IEC_INT>(HOLIDAYS[I].DAY));
        if (HOLIDAYS[I].USE == 1 && HOLIDAYS[I].MONTH > 0) {
            if (X_DATE == DATE_IN) {
                Y = true;
                NAME = HOLIDAYS[I].NAME;
                return;
            }
        } else if (HOLIDAYS[I].USE == 1 && HOLIDAYS[I].MONTH == 0) {
            if (DATE_ADD(OSTERN, static_cast<IEC_INT>(HOLIDAYS[I].DAY), 0, 0, 0) == DATE_IN) {
                Y = true;
                NAME = HOLIDAYS[I].NAME;
                return;
            }
        } else if (HOLIDAYS[I].USE < 0) {
            if (DAY_OF_WEEK(DATE_IN) == ABS(HOLIDAYS[I].USE) && DATE_IN < X_DATE && DATE_IN >= DATE_ADD(X_DATE, -7, 0, 0, 0)) {
                Y = true;
                NAME = HOLIDAYS[I].NAME;
                return;
            }
        }
    }
    if (!Y && (WDX == 5 && FRIDAY || WDX == 6 && SATURDAY || WDX == 7 && SUNDAY)) {
        Y = true;
        NAME = LANGUAGE.WEEKDAYS(LOCATION.LANGUAGE[LX], WDX);
    } else {
        NAME = "";
    }
}

