void HYST::operator()() {
    if (ON >= OFF) {
        if (IN < OFF) {
            Q = false;
            WIN = false;
        } else if (IN > ON) {
            Q = true;
            WIN = false;
        } else {
            WIN = true;
        }
    } else {
        if (IN > OFF) {
            Q = false;
            WIN = false;
        } else if (IN < ON) {
            Q = true;
            WIN = false;
        } else {
            WIN = true;
        }
    }
}

