IEC_REAL ARRAY_TREND(IEC_Ptr<Array1D<IEC_REAL, 0, 32000>> PT, IEC_UINT SIZE) {
    IEC_REAL ARRAY_TREND_result;
    IEC_UINT I;
    IEC_UINT STOP;
    IEC_REAL X;
    IEC_UINT STOP2;
    STOP = SHR(SIZE, 2) - 1;
    STOP2 = SHR(STOP, 1);
    for (I = 0; I <= STOP2; I++) {
        X = X - (*PT)[I];
    }
    if (EVEN(static_cast<IEC_DINT>(TO_INT(STOP)))) {
        for (I = STOP2; I <= STOP; I++) {
            X = X + (*PT)[I];
        }
    } else {
        for (I = STOP2 + 1; I <= STOP; I++) {
            X = X + (*PT)[I];
        }
    }
    ARRAY_TREND_result = X / TO_REAL(STOP2 + 1);
    return ARRAY_TREND_result;
}

IEC_REAL ARRAY_VAR(IEC_Ptr<Array1D<IEC_REAL, 0, 32000>> PT, IEC_UINT SIZE) {
    IEC_REAL ARRAY_VAR_result;
    IEC_REAL AVG;
    IEC_UINT I;
    IEC_UINT STOP;
    STOP = SHR(SIZE, 2) - 1;
    AVG = (*PT)[0];
    for (I = 1; I <= STOP; I++) {
        AVG = AVG + (*PT)[I];
    }
    AVG = AVG / TO_REAL(STOP + 1);
    ARRAY_VAR_result = ((*PT)[0] - AVG) * ((*PT)[0] - AVG);
    for (I = 1; I <= STOP; I++) {
        ARRAY_VAR_result = ARRAY_VAR_result + ((*PT)[I] - AVG) * ((*PT)[I] - AVG);
    }
    ARRAY_VAR_result = ARRAY_VAR_result / TO_REAL(STOP);
    return ARRAY_VAR_result;
}

