IEC_REAL ATAN2(IEC_REAL Y, IEC_REAL X) {
    IEC_REAL ATAN2_result;
    if (X > 0.0) {
        ATAN2_result = ATAN(Y / X);
    } else if (X < 0.0) {
        if (Y >= 0.0) {
            ATAN2_result = ATAN(Y / X) + MATH.PI;
        } else {
            ATAN2_result = ATAN(Y / X) - MATH.PI;
        }
    } else if (Y > 0.0) {
        ATAN2_result = MATH.PI05;
    } else if (Y < 0.0) {
        ATAN2_result = -MATH.PI05;
    } else {
        ATAN2_result = 0.0;
    }
    return ATAN2_result;
}

