IEC_DINT BINOM(IEC_INT N, IEC_INT K) {
    IEC_DINT BINOM_result;
    IEC_INT I;
    if (2 * K > N) {
        K = N - K;
    }
    if (K > N) {
        return BINOM_result;
    } else if (K == 0 || K == N) {
        BINOM_result = 1;
    } else if (K == 1) {
        BINOM_result = N;
    } else {
        BINOM_result = N;
        N = N + 1;
        for (I = 2; I <= K; I++) {
            BINOM_result = BINOM_result * (N - I) / I;
        }
    }
    return BINOM_result;
}

