IEC_INT BUFFER_COMP(IEC_Ptr<Array1D<IEC_BYTE, 0, 32767>> PT1, IEC_INT SIZE1, IEC_Ptr<Array1D<IEC_BYTE, 0, 32767>> PT2, IEC_INT SIZE2, IEC_INT START) {
    IEC_INT BUFFER_COMP_result;
    IEC_INT I;
    IEC_INT J;
    IEC_INT END;
    IEC_BYTE FIRSTBYTE;
    if (SIZE2 <= SIZE1) {
        END = SIZE1 - SIZE2;
        FIRSTBYTE = (*PT2)[0];
        for (I = START; I <= END; I++) {
            if ((*PT1)[I] == FIRSTBYTE) {
                J = 1;
                while (J < SIZE2) {
                    if ((*PT2)[J] != (*PT1)[J + I]) {
                        break;
                    }
                    J = J + 1;
                }
                if (J == SIZE2) {
                    BUFFER_COMP_result = I;
                    return BUFFER_COMP_result;
                }
            }
        }
    }
    BUFFER_COMP_result = -1;
    return BUFFER_COMP_result;
}

IEC_INT BUFFER_SEARCH(IEC_Ptr<Array1D<IEC_BYTE, 0, 32767>> PT, IEC_INT SIZE, IECStringVar<STRING_LENGTH> STR, IEC_INT POS, IEC_BOOL IGN) {
    IEC_INT BUFFER_SEARCH_result;
    IEC_Ptr<Array1D<IEC_BYTE, 0, 254>> PS;
    IEC_BYTE CHX;
    IEC_INT I;
    IEC_INT END;
    IEC_INT K;
    IEC_INT LX;
    PS = &(STR);
    LX = LEN(STR);
    END = MIN(SIZE - LX, SIZE - 1);
    LX = LX - 1;
    for (I = POS; I <= END; I++) {
        for (K = 0; K <= LX; K++) {
            if (IGN) {
                CHX = TO_UPPER((*PT)[I + K]);
            } else {
                CHX = (*PT)[I + K];
            }
            if ((*PS)[K] != CHX) {
                break;
            }
        }
        if (K > LX) {
            BUFFER_SEARCH_result = I;
            return BUFFER_SEARCH_result;
        }
    }
    BUFFER_SEARCH_result = -1;
    return BUFFER_SEARCH_result;
}

IECStringVar<STRING_LENGTH> BUFFER_TO_STRING(IEC_Ptr<Array1D<IEC_BYTE, 0, 32767>> PT, IEC_UINT SIZE, IEC_UINT START, IEC_UINT STOP) {
    IECStringVar<STRING_LENGTH> BUFFER_TO_STRING_result;
    IEC_Ptr<BYTE_t> PS;
    IEC_UINT I;
    IEC_UINT STP;
    IEC_UINT STA;
    PS = &(BUFFER_TO_STRING_result);
    if (SIZE == 0) {
        return BUFFER_TO_STRING_result;
    }
    STA = MIN(START, SIZE - 1);
    STP = MIN(STOP, SIZE - 1);
    if (TO_INT(STP - STA + 1) >= STRING_LENGTH) {
        STP = STA + TO_UINT(STRING_LENGTH) - 1;
    }
    for (I = STA; I <= STP; I++) {
        (*PS) = (*PT)[I];
        PS = PS + 1;
    }
    (*PS) = 0;
    return BUFFER_TO_STRING_result;
}

