IECStringVar<2> BYTE_TO_STRH(IEC_BYTE IN) {
    IECStringVar<2> BYTE_TO_STRH_result;
    IEC_BYTE TEMP;
    IEC_Ptr<BYTE_t> PT;
    PT = &(BYTE_TO_STRH_result);
    TEMP = SHR(IN, 4);
    if (TEMP <= 9) {
        TEMP = TEMP + 48;
    } else {
        TEMP = TEMP + 55;
    }
    (*PT) = TEMP;
    TEMP = IN & 0b00001111;
    if (TEMP <= 9) {
        TEMP = TEMP + 48;
    } else {
        TEMP = TEMP + 55;
    }
    PT = PT + 1;
    (*PT) = TEMP;
    PT = PT + 1;
    (*PT) = 0;
    return BYTE_TO_STRH_result;
}

IEC_REAL CABS(COMPLEX X) {
    IEC_REAL CABS_result;
    CABS_result = HYPOT(X.RE, X.IM);
    return CABS_result;
}

COMPLEX CACOS(COMPLEX X) {
    COMPLEX CACOS_result;
    COMPLEX Y;
    Y = CACOSH(X);
    CACOS_result.RE = Y.IM;
    CACOS_result.IM = -Y.RE;
    return CACOS_result;
}

COMPLEX CACOSH(COMPLEX X) {
    COMPLEX CACOSH_result;
    COMPLEX Y;
    Y.RE = (X.RE - X.IM) * (X.RE + X.IM) - 1.0;
    Y.IM = 2.0 * X.RE * X.IM;
    Y = CSQRT(Y);
    Y.RE = Y.RE + X.RE;
    Y.IM = Y.IM + X.IM;
    CACOSH_result = CLOG(Y);
    return CACOSH_result;
}

COMPLEX CADD(COMPLEX X, COMPLEX Y) {
    COMPLEX CADD_result;
    CADD_result.RE = X.RE + Y.RE;
    CADD_result.IM = X.IM + Y.IM;
    return CADD_result;
}

IECStringVar<STRING_LENGTH> CAPITALIZE(IECStringVar<STRING_LENGTH> STR) {
    IECStringVar<STRING_LENGTH> CAPITALIZE_result;
    IEC_Ptr<BYTE_t> PT;
    IEC_INT POS;
    IEC_INT L;
    IEC_BOOL FIRST = true;
    PT = &(CAPITALIZE_result);
    CAPITALIZE_result = STR;
    L = LEN(STR);
    for (POS = 1; POS <= L; POS++) {
        if (FIRST) {
            (*PT) = TO_UPPER((*PT));
        }
        FIRST = (*PT) == 32;
        PT = PT + 1;
    }
    return CAPITALIZE_result;
}

IEC_REAL CARG(COMPLEX X) {
    IEC_REAL CARG_result;
    CARG_result = ATAN2(X.IM, X.RE);
    return CARG_result;
}

COMPLEX CASIN(COMPLEX X) {
    COMPLEX CASIN_result;
    COMPLEX Y;
    Y.RE = -X.IM;
    Y.IM = X.RE;
    Y = CASINH(Y);
    CASIN_result.RE = Y.IM;
    CASIN_result.IM = -Y.RE;
    return CASIN_result;
}

COMPLEX CASINH(COMPLEX X) {
    COMPLEX CASINH_result;
    COMPLEX Y;
    Y.RE = (X.RE - X.IM) * (X.RE + X.IM) + 1.0;
    Y.IM = 2.0 * X.RE * X.IM;
    Y = CSQRT(Y);
    Y.RE = Y.RE + X.RE;
    Y.IM = Y.IM + X.IM;
    CASINH_result = CLOG(Y);
    return CASINH_result;
}

COMPLEX CATAN(COMPLEX X) {
    COMPLEX CATAN_result;
    IEC_REAL R2;
    IEC_REAL NUM;
    IEC_REAL DEN;
    R2 = X.RE * X.RE;
    DEN = 1.0 - R2 - X.IM * X.IM;
    CATAN_result.RE = 0.5 * ATAN(2.0 * X.RE / DEN);
    NUM = X.IM + 1.0;
    NUM = R2 + NUM * NUM;
    DEN = X.IM - 1.0;
    DEN = R2 + DEN * DEN;
    CATAN_result.IM = 0.25 * (LN(NUM) - LN(DEN));
    return CATAN_result;
}

COMPLEX CATANH(COMPLEX X) {
    COMPLEX CATANH_result;
    IEC_REAL I2;
    IEC_REAL NUM;
    IEC_REAL DEN;
    I2 = X.IM * X.IM;
    NUM = 1.0 + X.RE;
    NUM = I2 + NUM * NUM;
    DEN = 1.0 - X.RE;
    DEN = I2 + DEN * DEN;
    CATANH_result.RE = 0.25 * (LN(NUM) - LN(DEN));
    DEN = 1 - X.RE * X.RE - I2;
    CATANH_result.IM = 0.5 * ATAN(2.0 * X.IM / DEN);
    return CATANH_result;
}

IEC_REAL CAUCHY(IEC_REAL X, IEC_REAL T, IEC_REAL U) {
    IEC_REAL CAUCHY_result;
    IEC_REAL TMP;
    TMP = X - T;
    CAUCHY_result = MATH.PI_INV * U / (U * U + TMP * TMP);
    return CAUCHY_result;
}

IEC_REAL CAUCHYCD(IEC_REAL X, IEC_REAL T, IEC_REAL U) {
    IEC_REAL CAUCHYCD_result;
    CAUCHYCD_result = 0.5 + MATH.PI_INV * ATAN((X - T) / U);
    return CAUCHYCD_result;
}

COMPLEX CCON(COMPLEX X) {
    COMPLEX CCON_result;
    CCON_result.RE = X.RE;
    CCON_result.IM = -X.IM;
    return CCON_result;
}

COMPLEX CCOS(COMPLEX X) {
    COMPLEX CCOS_result;
    CCOS_result = CCOSH(CSET(-X.IM, X.RE));
    return CCOS_result;
}

COMPLEX CCOSH(COMPLEX X) {
    COMPLEX CCOSH_result;
    CCOSH_result.RE = COSH(X.RE) * COS(X.IM);
    CCOSH_result.IM = SINH(X.RE) * SIN(X.IM);
    return CCOSH_result;
}

COMPLEX CDIV(COMPLEX X, COMPLEX Y) {
    COMPLEX CDIV_result;
    IEC_REAL TEMP;
    TEMP = Y.RE * Y.RE + Y.IM * Y.IM;
    CDIV_result.RE = (X.RE * Y.RE + X.IM * Y.IM) / TEMP;
    CDIV_result.IM = (X.IM * Y.RE - X.RE * Y.IM) / TEMP;
    return CDIV_result;
}

IEC_INT CEIL(IEC_REAL X) {
    IEC_INT CEIL_result;
    CEIL_result = TO_INT(X);
    if (CEIL_result < X) {
        CEIL_result = CEIL_result + 1;
    }
    return CEIL_result;
}

IEC_DINT CEIL2(IEC_REAL X) {
    IEC_DINT CEIL2_result;
    CEIL2_result = TO_DINT(X);
    if (TO_REAL(CEIL2_result) < X) {
        CEIL2_result = CEIL2_result + 1;
    }
    return CEIL2_result;
}

COMPLEX CEXP(COMPLEX X) {
    COMPLEX CEXP_result;
    IEC_REAL TEMP;
    TEMP = EXP(X.RE);
    CEXP_result.RE = TEMP * COS(X.IM);
    CEXP_result.IM = TEMP * SIN(X.IM);
    return CEXP_result;
}

IEC_BYTE CHARCODE(IECStringVar<10> STR) {
    IEC_BYTE CHARCODE_result;
    IECStringVar<1> FOUND;
    IECStringVar<10> SEARCH;
    IEC_INT POS;
    IEC_INT I;
    if (LEN(STR) == 1) {
        CHARCODE_result = CODE(STR, 1);
    } else if (STR != "") {
        SEARCH = CONCAT("&", STR);
        SEARCH = CONCAT(SEARCH, ";");
        while (POS == 0 && (I < 4)) {
            I = I + 1;
            POS = FIND(SETUP.CHARNAMES[I], SEARCH);
        }
        FOUND = MID(SETUP.CHARNAMES[I], 1, POS - 1);
        CHARCODE_result = CODE(FOUND, 1);
    }
    return CHARCODE_result;
}

IECStringVar<10> CHARNAME(IEC_BYTE C) {
    IECStringVar<10> CHARNAME_result;
    IEC_INT POS;
    IEC_INT I;
    if (C != 0) {
        CHARNAME_result = CHR_TO_STRING(C);
        CHARNAME_result = CONCAT(CHARNAME_result, "&");
        CHARNAME_result = CONCAT(";", CHARNAME_result);
        while (POS == 0 && (I < 4)) {
            I = I + 1;
            POS = FIND(SETUP.CHARNAMES[I], CHARNAME_result);
        }
        if (POS > 0) {
            CHARNAME_result = MID(SETUP.CHARNAMES[I], 10, POS + 3);
            POS = FIND(CHARNAME_result, ";");
            CHARNAME_result = LEFT(CHARNAME_result, POS - 1);
        } else {
            CHARNAME_result = CHR_TO_STRING(C);
        }
    } else {
        CHARNAME_result = "";
    }
    return CHARNAME_result;
}

IEC_BOOL CHECK_PARITY(IEC_DWORD IN, IEC_BOOL P) {
    IEC_BOOL CHECK_PARITY_result;
    CHECK_PARITY_result = !P;
    while (IN > 0) {
        CHECK_PARITY_result = CHECK_PARITY_result ^ ((static_cast<uint64_t>(IN) >> 0) & 1) ^ ((static_cast<uint64_t>(IN) >> 1) & 1) ^ ((static_cast<uint64_t>(IN) >> 2) & 1) ^ ((static_cast<uint64_t>(IN) >> 3) & 1);
        IN = SHR(IN, 4);
    }
    return CHECK_PARITY_result;
}

IEC_BYTE CHK_REAL(IEC_REAL X) {
    IEC_BYTE CHK_REAL_result;
    IEC_Ptr<DWORD_t> PT;
    IEC_DWORD TMP;
    PT = &(X);
    TMP = ROL((*PT), 1);
    if (TMP < 0xFF000000) {
        CHK_REAL_result = 0x00;
    } else if (TMP == 0xFF000000) {
        CHK_REAL_result = 0x20;
    } else if (TMP == 0xFF000001) {
        CHK_REAL_result = 0x40;
    } else {
        CHK_REAL_result = 0x80;
    }
    return CHK_REAL_result;
}

IECStringVar<1> CHR_TO_STRING(IEC_BYTE C) {
    IECStringVar<1> CHR_TO_STRING_result;
    IEC_Ptr<BYTE_t> PT;
    PT = &(CHR_TO_STRING_result);
    (*PT) = C;
    PT = PT + 1;
    (*PT) = 0;
    return CHR_TO_STRING_result;
}

COMPLEX CINV(COMPLEX X) {
    COMPLEX CINV_result;
    IEC_REAL TEMP;
    TEMP = X.RE * X.RE + X.IM * X.IM;
    CINV_result.RE = X.RE / TEMP;
    CINV_result.IM = -X.IM / TEMP;
    return CINV_result;
}

IEC_REAL CIRCLE_A(IEC_REAL RX, IEC_REAL AX) {
    IEC_REAL CIRCLE_A_result;
    CIRCLE_A_result = RX * RX * 0.008726646 * AX;
    return CIRCLE_A_result;
}

IEC_REAL CIRCLE_C(IEC_REAL RX, IEC_REAL AX) {
    IEC_REAL CIRCLE_C_result;
    CIRCLE_C_result = 0.017453293 * RX * AX;
    return CIRCLE_C_result;
}

IEC_REAL CIRCLE_SEG(IEC_REAL RX, IEC_REAL HX) {
    IEC_REAL CIRCLE_SEG_result;
    if (RX > 0.0) {
        CIRCLE_SEG_result = 2.0 * ACOS(1.0 - LIMIT(0.0, HX / RX, 2.0));
        CIRCLE_SEG_result = (CIRCLE_SEG_result - SIN(CIRCLE_SEG_result)) * RX * RX / 2.0;
    }
    return CIRCLE_SEG_result;
}

IECStringVar<STRING_LENGTH> CLEAN(IECStringVar<STRING_LENGTH> IN, IECStringVar<80> CX) {
    IECStringVar<STRING_LENGTH> CLEAN_result;
    IEC_INT POS = 1;
    IEC_INT STOP;
    CLEAN_result = IN;
    STOP = LEN(IN);
    while (POS <= STOP) {
        if (FIND(CX, MID(CLEAN_result, 1, POS)) > 0) {
            POS = POS + 1;
        } else {
            CLEAN_result = DELETE_STR(CLEAN_result, 1, POS);
            STOP = STOP - 1;
        }
    }
    return CLEAN_result;
}

COMPLEX CLOG(COMPLEX X) {
    COMPLEX CLOG_result;
    CLOG_result.RE = LN(HYPOT(X.RE, X.IM));
    CLOG_result.IM = ATAN2(X.IM, X.RE);
    return CLOG_result;
}

IEC_BOOL CMP(IEC_REAL X, IEC_REAL Y, IEC_INT N) {
    IEC_BOOL CMP_result;
    IEC_REAL TMP;
    TMP = ABS(X);
    if (TMP > 0.0) {
        TMP = EXP10(TO_REAL(FLOOR(LOG(TMP)) - N + 1));
    } else {
        TMP = EXP10(TMP);
    }
    CMP_result = ABS(X - Y) < TMP;
    return CMP_result;
}

COMPLEX CMUL(COMPLEX X, COMPLEX Y) {
    COMPLEX CMUL_result;
    CMUL_result.RE = X.RE * Y.RE - X.IM * Y.IM;
    CMUL_result.IM = X.RE * Y.IM + X.IM * Y.RE;
    return CMUL_result;
}

IEC_BYTE CODE(IECStringVar<STRING_LENGTH> STR, IEC_INT POS) {
    IEC_BYTE CODE_result;
    IEC_Ptr<BYTE_t> PT;
    if (POS < 1 || POS > LEN(STR)) {
        CODE_result = 0;
        return CODE_result;
    } else {
        PT = &(STR) + TO_DWORD(POS - 1);
        CODE_result = (*PT);
    }
    return CODE_result;
}

IEC_REAL CONE_V(IEC_REAL RX, IEC_REAL HX) {
    IEC_REAL CONE_V_result;
    CONE_V_result = 1.047197551 * RX * RX * HX;
    return CONE_V_result;
}

IEC_REAL COSH(IEC_REAL X) {
    IEC_REAL COSH_result;
    IEC_REAL T;
    T = EXP(X);
    COSH_result = (1.0 / T + T) * 0.5;
    return COSH_result;
}

IEC_REAL COTH(IEC_REAL X) {
    IEC_REAL COTH_result;
    if (X > 20.0) {
        COTH_result = 1.0;
    } else if (X < -20.0) {
        COTH_result = -1.0;
    } else {
        COTH_result = 1.0 + 2.0 / (EXP(X * 2.0) - 1.0);
    }
    return COTH_result;
}

IEC_INT COUNT_CHAR(IECStringVar<STRING_LENGTH> STR, IEC_BYTE CHR) {
    IEC_INT COUNT_CHAR_result;
    IEC_INT L;
    IEC_Ptr<BYTE_t> PT;
    IEC_INT POS;
    PT = &(STR);
    L = LEN(STR);
    COUNT_CHAR_result = 0;
    for (POS = 1; POS <= L; POS++) {
        if ((*PT) == CHR) {
            COUNT_CHAR_result = COUNT_CHAR_result + 1;
        }
        PT = PT + 1;
    }
    return COUNT_CHAR_result;
}

IEC_INT COUNT_SUBSTRING(IEC_STRING SEARCH, IEC_STRING STR) {
    IEC_INT COUNT_SUBSTRING_result;
    IEC_INT POS;
    IEC_INT SIZE;
    COUNT_SUBSTRING_result = 0;
    SIZE = LEN(SEARCH);
    do {
        POS = FIND(STR, SEARCH);
        if (POS > 0) {
            STR = REPLACE(STR, "", SIZE, POS);
            COUNT_SUBSTRING_result = COUNT_SUBSTRING_result + 1;
        }
    } while (!(POS == 0));
    return COUNT_SUBSTRING_result;
}

COMPLEX CPOL(IEC_REAL L, IEC_REAL A) {
    COMPLEX CPOL_result;
    CPOL_result.RE = L * COS(A);
    CPOL_result.IM = L * SIN(A);
    return CPOL_result;
}

COMPLEX CPOW(COMPLEX X, COMPLEX Y) {
    COMPLEX CPOW_result;
    CPOW_result = CEXP(CMUL(Y, CLOG(X)));
    return CPOW_result;
}

IEC_DWORD CRC_GEN(IEC_Ptr<Array1D<IEC_BYTE, 0, 32000>> PT, IEC_INT SIZE, IEC_INT PL, IEC_DWORD PN, IEC_DWORD INIT, IEC_BOOL REV_IN, IEC_BOOL REV_OUT, IEC_DWORD XOR_OUT) {
    IEC_DWORD CRC_GEN_result;
    IEC_INT POS;
    IEC_INT SHIFT;
    IEC_BYTE DX;
    IEC_INT BITS;
    SHIFT = 32 - PL;
    PN = SHL(PN, SHIFT);
    for (POS = 0; POS <= 3; POS++) {
        if (REV_IN) {
            CRC_GEN_result = SHL(CRC_GEN_result, 8) | REVERSE((*PT)[POS]);
        } else {
            CRC_GEN_result = SHL(CRC_GEN_result, 8) || (*PT)[POS];
        }
    }
    POS = 4;
    CRC_GEN_result = CRC_GEN_result ^ SHL(INIT, SHIFT);
    while (POS < SIZE) {
        if (REV_IN) {
            DX = REVERSE((*PT)[POS]);
        } else {
            DX = (*PT)[POS];
        }
        POS = POS + 1;
        for (BITS = 0; BITS <= 7; BITS++) {
            if (((static_cast<uint64_t>(CRC_GEN_result) >> 31) & 1)) {
                CRC_GEN_result = (SHL(CRC_GEN_result, 1) | TO_DWORD(((static_cast<uint64_t>(DX) >> 7) & 1))) ^ PN;
            } else {
                CRC_GEN_result = SHL(CRC_GEN_result, 1) | TO_DWORD(((static_cast<uint64_t>(DX) >> 7) & 1));
            }
            DX = SHL(DX, 1);
        }
    }
    for (BITS = 0; BITS <= 31; BITS++) {
        if (((static_cast<uint64_t>(CRC_GEN_result) >> 31) & 1)) {
            CRC_GEN_result = (SHL(CRC_GEN_result, 1)) ^ PN;
        } else {
            CRC_GEN_result = SHL(CRC_GEN_result, 1);
        }
    }
    CRC_GEN_result = SHR(CRC_GEN_result, SHIFT) ^ XOR_OUT;
    if (REV_OUT) {
        CRC_GEN_result = REFLECT(CRC_GEN_result, PL);
    }
    return CRC_GEN_result;
}

