    IEC_REAL TEMP;
    TEMP = HYPOT(X.RE, X.IM);
    CSQRT_result.RE = SQRT(0.5 * (TEMP + X.RE));
    CSQRT_result.IM = SGN(X.IM) * SQRT(0.5 * (TEMP - X.RE));
    return CSQRT_result;
