IEC_DATE DATE_ADD(IEC_DATE IDATE, IEC_INT D, IEC_INT W, IEC_INT M, IEC_INT Y) {
    IEC_DATE DATE_ADD_result;
    IEC_INT MO;
    IEC_INT YR;
    IEC_INT DM;
    DATE_ADD_result = TO_DATE(TO_UDINT(IDATE) + TO_UDINT(D + W * 7) * static_cast<IEC_UDINT>(86400));
    YR = Y + YEAR_OF_DATE(DATE_ADD_result);
    MO = M + MONTH_OF_DATE(DATE_ADD_result);
    DM = DAY_OF_MONTH(DATE_ADD_result);
    while (MO > 12) {
        MO = MO - 12;
        YR = YR + 1;
    }
    while (MO < 1) {
        MO = MO + 12;
        YR = YR - 1;
    }
    DATE_ADD_result = SET_DATE(YR, MO, DM);
    return DATE_ADD_result;
}

