IEC_INT DEC_TO_INT(IECStringVar<10> DEC) {
    IEC_INT DEC_TO_INT_result;
    IEC_Ptr<BYTE_t> PT;
    IEC_INT I;
    IEC_BYTE X;
    IEC_BOOL SIGN;
    IEC_INT STOP;
    PT = &(DEC);
    STOP = LEN(DEC);
    for (I = 1; I <= STOP; I++) {
        X = (*PT);
        if (X > 47 && X < 58) {
            DEC_TO_INT_result = DEC_TO_INT_result * 10 + X - 48;
        } else if (X == 45 && DEC_TO_INT_result == 0) {
            SIGN = true;
        }
        PT = PT + 1;
    }
    if (SIGN) {
        DEC_TO_INT_result = -DEC_TO_INT_result;
    }
    return DEC_TO_INT_result;
}

IEC_REAL DEG(IEC_REAL RAD) {
    IEC_REAL DEG_result;
    DEG_result = MODR(57.29577951308232 * RAD, 360.0);
    return DEG_result;
}

IECStringVar<3> DEG_TO_DIR(IEC_INT DEG, IEC_INT N, IEC_INT L) {
    IECStringVar<3> DEG_TO_DIR_result;
    IEC_INT LY;
    if (L == 0) {
        LY = LANGUAGE.DEFAULT;
    } else {
        LY = MIN(L, LANGUAGE.LMAX);
    }
    DEG_TO_DIR_result = LANGUAGE.DIRS(LY, ((SHL(DEG, N - 1) + 45) / 90) % SHL(static_cast<IEC_INT>(2), N) * SHR(static_cast<IEC_INT>(8), N));
    return DEG_TO_DIR_result;
}

IECStringVar<STRING_LENGTH> DEL_CHARS(IECStringVar<STRING_LENGTH> IN, IECStringVar<80> CX) {
    IECStringVar<STRING_LENGTH> DEL_CHARS_result;
    IEC_INT POS = 1;
    IEC_INT STOP;
    DEL_CHARS_result = IN;
    STOP = LEN(IN);
    while (POS <= STOP) {
        if (FIND(CX, MID(DEL_CHARS_result, 1, POS)) > 0) {
            DEL_CHARS_result = DELETE_STR(DEL_CHARS_result, 1, POS);
            STOP = STOP - 1;
        } else {
            POS = POS + 1;
        }
    }
    return DEL_CHARS_result;
}

IEC_BOOL DIFFER(IEC_REAL IN1, IEC_REAL IN2, IEC_REAL X) {
    IEC_BOOL DIFFER_result;
    DIFFER_result = ABS(IN1 - IN2) > X;
    return DIFFER_result;
}

IEC_INT DIR_TO_DEG(IECStringVar<3> DIR, IEC_INT L) {
    IEC_INT DIR_TO_DEG_result;
    IEC_INT LY;
    IEC_INT I;
    if (L == 0) {
        LY = LANGUAGE.DEFAULT;
    } else {
        LY = MIN(L, LANGUAGE.LMAX);
    }
    for (I = 0; I <= 15; I++) {
        if (LANGUAGE.DIRS(LY, I) == DIR) {
            break;
        }
    }
    DIR_TO_DEG_result = SHR(I * 45 + 1, 1);
    return DIR_TO_DEG_result;
}

IEC_BOOL DST(IEC_DT UTC) {
    IEC_BOOL DST_result;
    IEC_INT YR;
    IEC_DWORD YR4;
    IEC_DWORD LTC;
    IEC_DWORD IDATE;
    YR = YEAR_OF_DATE(TO_DATE(UTC));
    LTC = TO_DWORD(UTC);
    IDATE = TO_DWORD(SET_DT(YR, 3, 31, 1, 0, 0));
    YR4 = SHR(5 * TO_DWORD(YR), 2) + 1;
    DST_result = (IDATE - ((YR4 + 3) % 7) * 86400 <= LTC) && (IDATE + (214 - (YR4) % 7) * 86400 > LTC);
    return DST_result;
}

SDT DT2_TO_SDT(IEC_DATE DI, IEC_TOD TI) {
    SDT DT2_TO_SDT_result;
    DT2_TO_SDT_result.YEAR = YEAR_OF_DATE(DI);
    DT2_TO_SDT_result.MONTH = MONTH_OF_DATE(DI);
    DT2_TO_SDT_result.DAY = DAY_OF_MONTH(DI);
    DT2_TO_SDT_result.WEEKDAY = DAY_OF_WEEK(DI);
    DT2_TO_SDT_result.MS = TO_INT(TO_DWORD(TI) % 1000);
    DT2_TO_SDT_result.SECOND = TO_INT((TO_DWORD(TI) / 1000) % 60);
    DT2_TO_SDT_result.MINUTE = TO_INT((TO_DWORD(TI) / 60000) % 60);
    DT2_TO_SDT_result.HOUR = TO_INT(TO_DWORD(TI) / 3600000);
    return DT2_TO_SDT_result;
}

SDT DT_TO_SDT(IEC_DT DTI) {
    SDT DT_TO_SDT_result;
    IEC_DATE TMP;
    IEC_DWORD TDT;
    TMP = TO_DATE(DTI);
    TDT = TO_DWORD(DTI) - TO_DWORD(TMP);
    DT_TO_SDT_result.YEAR = YEAR_OF_DATE(TMP);
    DT_TO_SDT_result.MONTH = MONTH_OF_DATE(TMP);
    DT_TO_SDT_result.DAY = DAY_OF_MONTH(TMP);
    DT_TO_SDT_result.WEEKDAY = DAY_OF_WEEK(TMP);
    DT_TO_SDT_result.SECOND = TO_INT(TDT % 60);
    DT_TO_SDT_result.MINUTE = TO_INT((TDT / 60) % 60);
    DT_TO_SDT_result.HOUR = TO_INT(TDT / 3600);
    return DT_TO_SDT_result;
}

IEC_STRING DT_TO_STRF(IEC_DT DTI, IEC_INT MS, IEC_STRING FMT, IEC_INT LANG) {
    IEC_STRING DT_TO_STRF_result;
    IECStringVar<1> FILL = "0";
    IECStringVar<1> BLANK = " ";
    IEC_INT LY;
    IEC_DATE DX;
    IECStringVar<10> FS;
    IEC_TOD TD;
    IEC_INT TMP;
    IEC_INT POS;
    IEC_INT F;
    if (LANG < 1) {
        LY = LANGUAGE.DEFAULT;
    } else {
        LY = MIN(LANGUAGE.LMAX, LANG);
    }
    DX = TO_DATE(DTI);
    TD = TO_TOD(DTI);
    DT_TO_STRF_result = FMT;
    POS = FIND(DT_TO_STRF_result, "#");
    while (POS > 0) {
        F = CODE(DT_TO_STRF_result, POS + 1);
        FS = "";
        switch (F) {
            case 65:
                FS = TO_STRING(YEAR_OF_DATE(DX));
                break;
            case 66:
                FS = RIGHT(TO_STRING(YEAR_OF_DATE(DX)), 2);
                break;
            case 67:
                FS = TO_STRING(MONTH_OF_DATE(DX));
                break;
            case 68:
                FS = TO_STRING(MONTH_OF_DATE(DX));
                if (LEN(FS) < 2) {
                    FS = CONCAT("0", FS);
                }
                break;
            case 69:
                FS = MONTH_TO_STRING(MONTH_OF_DATE(DX), LY, 3);
                break;
            case 70:
                FS = MONTH_TO_STRING(MONTH_OF_DATE(DX), LY, 0);
                break;
            case 71:
                FS = TO_STRING(DAY_OF_MONTH(DX));
                break;
            case 72:
                FS = TO_STRING(DAY_OF_MONTH(DX));
                if (LEN(FS) < 2) {
                    FS = CONCAT(FILL, FS);
                }
                break;
            case 73:
                FS = TO_STRING(DAY_OF_WEEK(DX));
                break;
            case 74:
                FS = WEEKDAY_TO_STRING(DAY_OF_WEEK(DX), LY, 2);
                break;
            case 75:
                FS = WEEKDAY_TO_STRING(DAY_OF_WEEK(DX), LY, 0);
                break;
            case 76:
                if (TD >= 0) {
                    FS = "PM";
                } else {
                    FS = "AM";
                }
                break;
            case 77:
                FS = TO_STRING(HOUR(TD));
                break;
            case 78:
                FS = TO_STRING(HOUR(TD));
                if (LEN(FS) < 2) {
                    FS = CONCAT(FILL, FS);
                }
                break;
            case 79:
                TMP = HOUR(TD) % 12;
                if (TMP == 0) {
                    TMP = 12;
                }
                FS = TO_STRING(TMP);
                break;
            case 80:
                TMP = HOUR(TD) % 12;
                if (TMP == 0) {
                    TMP = 12;
                }
                FS = TO_STRING(TMP);
                if (LEN(FS) < 2) {
                    FS = CONCAT(FILL, FS);
                }
                break;
            case 81:
                FS = TO_STRING(MINUTE(TD));
                break;
            case 82:
                FS = TO_STRING(MINUTE(TD));
                if (LEN(FS) < 2) {
                    FS = CONCAT(FILL, FS);
                }
                break;
            case 83:
                FS = TO_STRING(TO_INT(SECOND(TD)));
                break;
            case 84:
                FS = TO_STRING(TO_INT(SECOND(TD)));
                if (LEN(FS) < 2) {
                    FS = CONCAT(FILL, FS);
                }
                break;
            case 85:
                FS = TO_STRING(MS);
                break;
            case 86:
                FS = TO_STRING(MS);
                FS = CONCAT("00", FS);
                FS = RIGHT(FS, 3);
                break;
            case 87:
                FS = TO_STRING(DAY_OF_MONTH(DX));
                if (LEN(FS) < 2) {
                    FS = CONCAT(BLANK, FS);
                }
                break;
            case 88:
                FS = TO_STRING(MONTH_OF_DATE(DX));
                if (LEN(FS) < 2) {
                    FS = CONCAT(BLANK, FS);
                }
                break;
        }
        DT_TO_STRF_result = REPLACE(DT_TO_STRF_result, FS, 2, POS);
        POS = FIND(DT_TO_STRF_result, "#");
    }
    return DT_TO_STRF_result;
}

