IECStringVar<32> DWORD_TO_STRB(IEC_DWORD IN) {
    IECStringVar<32> DWORD_TO_STRB_result;
    IEC_Ptr<BYTE_t> PT;
    IEC_INT I;
    PT = &(DWORD_TO_STRB_result);
    for (I = 1; I <= 32; I++) {
        (*PT) = TO_BYTE(((static_cast<uint64_t>(IN) >> 31) & 1)) + 48;
        IN = SHL(IN, 1);
        PT = PT + 1;
    }
    (*PT) = 0;
    return DWORD_TO_STRB_result;
}

