IECStringVar<8> DWORD_TO_STRH(IEC_DWORD IN) {
    IECStringVar<8> DWORD_TO_STRH_result;
    IEC_INT I;
    IEC_BYTE TEMP;
    IEC_Ptr<BYTE_t> PT;
    PT = &(DWORD_TO_STRH_result) + 8;
    (*PT) = 0;
    for (I = 1; I <= 8; I++) {
        PT = PT - 1;
        TEMP = TO_BYTE(IN & 0x0000000F);
        if (TEMP <= 9) {
            TEMP = TEMP + 48;
        } else {
            TEMP = TEMP + 55;
        }
        (*PT) = TEMP;
        IN = SHR(IN, 4);
    }
    return DWORD_TO_STRH_result;
}

