IECStringVar<STRING_LENGTH> EXEC(IECStringVar<STRING_LENGTH> STR) {
    IECStringVar<STRING_LENGTH> EXEC_result;
    IEC_INT POS;
    IEC_REAL R1;
    IEC_REAL R2;
    IECStringVar<10> OPERATOR;
    EXEC_result = UPPERCASE(TRIM(STR));
    POS = FINDB_NONUM(EXEC_result);
    if (POS > 1) {
        R1 = TO_REAL(LEFT(EXEC_result, POS - 1));
    }
    R2 = TO_REAL(RIGHT(EXEC_result, LEN(EXEC_result) - POS));
    EXEC_result = LEFT(EXEC_result, POS);
    POS = FINDB_NUM(EXEC_result);
    OPERATOR = RIGHT(EXEC_result, LEN(EXEC_result) - POS);
    if (OPERATOR == "" && LEN(STR) == 0) {
        EXEC_result = "";
        return EXEC_result;
    } else if (OPERATOR == "") {
        EXEC_result = STR;
        return EXEC_result;
    }
    if (OPERATOR == "^") {
        EXEC_result = TO_STRING(EXPT(R1, R2));
    } else if (OPERATOR == "SQRT") {
        EXEC_result = TO_STRING(SQRT(R2));
    } else if (OPERATOR == "SIN") {
        EXEC_result = TO_STRING(SIN(R2));
    } else if (OPERATOR == "COS") {
        EXEC_result = TO_STRING(COS(R2));
    } else if (OPERATOR == "TAN") {
        EXEC_result = TO_STRING(TAN(R2));
    } else if (OPERATOR == "*") {
        EXEC_result = TO_STRING(R1 * R2);
    } else if (OPERATOR == "/") {
        if (R2 != 0) {
            EXEC_result = TO_STRING(R1 / R2);
        } else {
            EXEC_result = "ERROR";
        }
    } else if (OPERATOR == "+") {
        EXEC_result = TO_STRING(R1 + R2);
    } else if (OPERATOR == "-") {
        EXEC_result = TO_STRING(R1 - R2);
    } else {
        EXEC_result = "ERROR";
    }
    if (EXEC_result == "ERROR") {
        return EXEC_result;
    } else if (FIND(EXEC_result, ".") == 0) {
        EXEC_result = CONCAT(EXEC_result, ".0");
    } else if (RIGHT(EXEC_result, 1) == ".") {
        EXEC_result = CONCAT(EXEC_result, "0");
    }
    return EXEC_result;
}

