IEC_REAL EXPN(IEC_REAL X, IEC_INT N) {
    IEC_REAL EXPN_result;
    IEC_BOOL SIGN;
    SIGN = ((static_cast<uint64_t>(N) >> 15) & 1);
    N = ABS(N);
    if (((static_cast<uint64_t>(N) >> 0) & 1)) {
        EXPN_result = X;
    } else {
        EXPN_result = 1.0;
    }
    N = SHR(N, 1);
    while (N > 0) {
        X = X * X;
        if (((static_cast<uint64_t>(N) >> 0) & 1)) {
            EXPN_result = EXPN_result * X;
        }
        N = SHR(N, 1);
    }
    if (SIGN) {
        EXPN_result = 1.0 / EXPN_result;
    }
    return EXPN_result;
}

