IEC_REAL FLOAT_TO_REAL(IECStringVar<20> FLT) {
    IEC_REAL FLOAT_TO_REAL_result;
    IEC_Ptr<Array1D<IEC_BYTE, 1, 20>> PT;
    IEC_INT I;
    IEC_BYTE X;
    IEC_INT SIGN = 1;
    IEC_INT STOP;
    IEC_DINT TMP;
    IEC_INT D;
    PT = &(FLT);
    STOP = LEN(FLT);
    for (I = 1; I <= STOP; I++) {
        X = (*PT)[I];
        if (X > 47 && X < 58 || X == 46) {
            break;
        } else if (X == 45) {
            SIGN = -1;
        }
    }
    for (I = I; I <= STOP; I++) {
        X = (*PT)[I];
        if (X == 44 || X == 46 || X == 69 || X == 101) {
            break;
        } else if (X > 47 && X < 58) {
            TMP = TMP * 10 + X - 48;
        }
    }
    if (X == 44 || X == 46) {
        for (I = I + 1; I <= STOP; I++) {
            X = (*PT)[I];
            if (X == 69 || X == 101) {
                break;
            } else if (X > 47 && X < 58) {
                TMP = TMP * 10 + X - 48;
                D = D - 1;
            }
        }
    }
    if (X == 69 || X == 101) {
        D = D + DEC_TO_INT(RIGHT(FLT, STOP - I));
    }
    FLOAT_TO_REAL_result = EXPN(static_cast<IEC_REAL>(10), D) * TO_REAL(TMP * SIGN);
    return FLOAT_TO_REAL_result;
}

