IEC_DT FSTRING_TO_DT(IECStringVar<60> SDT, IECStringVar<60> FMT) {
    IEC_DT FSTRING_TO_DT_result;
    IECStringVar<1> IGNORE = "*";
    IECStringVar<1> FCHAR = "#";
    IECStringVar<1> C;
    IECStringVar<20> TMP;
    IEC_INT END;
    IEC_INT DY = 1970;
    IEC_INT DM = 1;
    IEC_INT DD = 1;
    IEC_INT TH;
    IEC_INT TM;
    IEC_INT TS;
    while (FMT != "") {
        C = LEFT(FMT, 1);
        if (C == IGNORE) {
            FMT = DELETE_STR(FMT, 1, 1);
            SDT = DELETE_STR(SDT, 1, 1);
        } else if (C == FCHAR) {
            C = MID(FMT, 1, 2);
            FMT = DELETE_STR(FMT, 2, 1);
            if (FMT == "") {
                TMP = SDT;
            } else {
                END = FIND(SDT, LEFT(FMT, 1)) - 1;
                TMP = LEFT(SDT, END);
                SDT = DELETE_STR(SDT, END, 1);
            }
            if (C == "Y") {
                DY = TO_INT(TMP);
                if (DY < 100) {
                    DY = DY + 2000;
                }
            } else if (C == "M") {
                DM = TO_INT(TMP);
            } else if (C == "N") {
                DM = FSTRING_TO_MONTH(TMP, 0);
            } else if (C == "D") {
                DD = TO_INT(TMP);
            } else if (C == "h") {
                TH = TO_INT(TMP);
            } else if (C == "m") {
                TM = TO_INT(TMP);
            } else if (C == "s") {
                TS = TO_INT(TMP);
            }
        } else if (C == LEFT(SDT, 1)) {
            FMT = DELETE_STR(FMT, 1, 1);
            SDT = DELETE_STR(SDT, 1, 1);
        } else {
            return FSTRING_TO_DT_result;
        }
    }
    FSTRING_TO_DT_result = SET_DT(DY, DM, DD, TH, TM, TS);
    return FSTRING_TO_DT_result;
}

