IEC_INT GCD(IEC_DINT A, IEC_DINT B) {
    IEC_INT GCD_result;
    IEC_DINT T;
    if (A == 0) {
        GCD_result = TO_INT(ABS(B));
    } else if (B == 0) {
        GCD_result = TO_INT(ABS(A));
    } else {
        A = ABS(A);
        B = ABS(B);
        GCD_result = 1;
        while (!(((static_cast<uint64_t>(A) >> 0) & 1) || ((static_cast<uint64_t>(B) >> 0) & 1))) {
            A = SHR(A, 1);
            B = SHR(B, 1);
            GCD_result = SHL(GCD_result, 1);
        }
        while (A > 0) {
            if (!(((static_cast<uint64_t>(A) >> 0) & 1))) {
                A = SHR(A, 1);
            } else if (!(((static_cast<uint64_t>(B) >> 0) & 1))) {
                B = SHR(B, 1);
            } else {
                T = SHR(ABS(A - B), 1);
                if (A < B) {
                    B = T;
                } else {
                    A = T;
                }
            }
        }
        GCD_result = GCD_result * TO_INT(B);
    }
    return GCD_result;
}

