IEC_REAL LAMBERT_W(IEC_REAL X) {
    IEC_REAL LAMBERT_W_result;
    IEC_REAL W;
    IEC_INT I;
    IEC_REAL WE;
    IEC_REAL W1E;
    IEC_DWORD LAST;
    IEC_REAL EWX;
    if (X < -0.367879441171442) {
        LAMBERT_W_result = -1000.0;
        return LAMBERT_W_result;
    } else if (X == 0.0) {
        return LAMBERT_W_result;
    } else if (X <= 500.0) {
        W = LN(X + 1.0);
        W = 0.665 * (1.0 + 0.0195 * W) * W + 0.04;
    } else {
        W = LN(X - 4.0) - (1.0 - 1.0 / LN(X)) * LN(LN(X));
    }
    for (I = 0; I <= 5; I++) {
        EWX = EXP(W);
        WE = W * EWX - X;
        W1E = (W + 1.0) * EWX;
        LAST = REAL_TO_DW(W) & 0xFFFFFFFC;
        W = W - (WE / (W1E - (W + 2.0) * WE / (2.0 * W + 2.0)));
        if ((REAL_TO_DW(W) & 0xFFFFFFFC) == LAST) {
            break;
        }
    }
    LAMBERT_W_result = W;
    return LAMBERT_W_result;
}

