IEC_BOOL LIST_CLEAN(IEC_BYTE SEP, IEC_STRING& LIST) {
    IEC_BOOL LIST_CLEAN_result;
    IEC_Ptr<Array1D<IEC_BYTE, 1, 254>> PT;
    IEC_INT READ = 1;
    IEC_INT WRITE = 1;
    IEC_BYTE LAST;
    IEC_BYTE C;
    PT = &(LIST);
    for (READ = 1; READ <= LIST_LENGTH; READ++) {
        C = (*PT)[READ];
        if (C == 0) {
            break;
        } else if (C != SEP || SEP != LAST) {
            (*PT)[WRITE] = C;
            WRITE = WRITE + 1;
        }
        LAST = C;
    }
    if (LAST == SEP) {
        WRITE = WRITE - 1;
    }
    if (WRITE <= STRING_LENGTH) {
        (*PT)[WRITE] = 0;
    }
    LIST_CLEAN_result = true;
    return LIST_CLEAN_result;
}

