IEC_INT WORK_WEEK(IEC_DATE IDATE) {
    IEC_INT WORK_WEEK_result;
    IEC_DATE D1;
    IEC_INT W1;
    IEC_DWORD DS;
    IEC_INT YR;
    IEC_INT W31;
    IEC_INT W01;
    IEC_INT WM;
    YR = YEAR_OF_DATE(IDATE);
    D1 = YEAR_BEGIN(YR);
    W1 = DAY_OF_WEEK(D1);
    if (W1 < 5) {
        DS = TO_DWORD(D1) - TO_DWORD(W1 + 6) * 86400;
    } else {
        DS = TO_DWORD(D1) - TO_DWORD(W1 - 1) * 86400;
    }
    WORK_WEEK_result = TO_INT((TO_DWORD(IDATE) - DS) / 604800);
    if (WORK_WEEK_result == 0) {
        if (W1 > 1) {
            W31 = W1 - 1;
        } else {
            W31 = 7;
        }
        if (LEAP_YEAR(YR - 1) && W31 > 1) {
            W01 = W31 - 1;
        } else {
            W1 = 7;
        }
        WORK_WEEK_result = 52 + TO_INT(W31 == 4 || W01 == 4);
    } else {
        if (LEAP_YEAR(YR)) {
            if (W1 < 7) {
                W31 = W1 + 1;
            } else {
                W31 = 1;
            }
        } else {
            W31 = W1;
        }
        WM = 52 + TO_INT(W31 == 4 || W1 == 4);
        if (WORK_WEEK_result > WM) {
            WORK_WEEK_result = 1;
        }
    }
    return WORK_WEEK_result;
}

