IEC_BOOL _ARRAY_SHUFFLE(IEC_Ptr<Array1D<IEC_REAL, 0, 32000>> PT, IEC_UINT SIZE) {
    IEC_BOOL _ARRAY_SHUFFLE_result;
    IEC_REAL TEMP;
    IEC_INT POS;
    IEC_INT I;
    IEC_INT STOP;
    STOP = TO_INT(SHR(SIZE, 2) - 1);
    for (I = 0; I <= STOP; I++) {
        POS = RDM2(I + POS, 0, STOP);
        TEMP = (*PT)[I];
        (*PT)[I] = (*PT)[POS];
        (*PT)[POS] = TEMP;
    }
    _ARRAY_SHUFFLE_result = true;
    return _ARRAY_SHUFFLE_result;
}

IEC_BOOL _ARRAY_SORT(IEC_Ptr<Array1D<IEC_REAL, 1, 32000>> PT, IEC_UINT SIZE) {
    IEC_BOOL _ARRAY_SORT_result;
    IEC_UINT STACK_COUNT;
    Array1D<IEC_UINT, 1, 32> STACK;
    IEC_UINT LINKS;
    IEC_UINT RECHTS;
    IEC_REAL PIVOT;
    IEC_UINT I;
    IEC_UINT J;
    IEC_BOOL ENDE_INNEN;
    IEC_BOOL ENDE_AUSSEN;
    IEC_REAL TMP;
    LINKS = 1;
    RECHTS = SHR(SIZE, 2);
    STACK_COUNT = 1;
    while (!ENDE_AUSSEN) {
        if (LINKS < RECHTS) {
            PIVOT = (*PT)[SHR(RECHTS + LINKS, 1)];
            I = LINKS - 1;
            J = RECHTS + 1;
            ENDE_INNEN = false;
            do {
                do {
                    I = I + 1;
                } while (!(((*PT)[I] >= PIVOT) || !(I < RECHTS)));
                do {
                    J = J - 1;
                } while (!(((*PT)[J] <= PIVOT) || !(J > LINKS)));
                if (I >= J) {
                    ENDE_INNEN = true;
                } else {
                    TMP = (*PT)[J];
                    (*PT)[J] = (*PT)[I];
                    (*PT)[I] = TMP;
                }
            } while (!(ENDE_INNEN));
            STACK[STACK_COUNT] = RECHTS;
            if (STACK_COUNT < 32) {
                STACK_COUNT = STACK_COUNT + 1;
            } else {
                ENDE_AUSSEN = true;
                _ARRAY_SORT_result = false;
            }
            RECHTS = MAX(LINKS, I - 1);
        } else {
            if (STACK_COUNT == 1) {
                ENDE_AUSSEN = true;
            } else {
                LINKS = RECHTS + 1;
                STACK_COUNT = STACK_COUNT - 1;
                RECHTS = STACK[STACK_COUNT];
            }
        }
    }
    _ARRAY_SORT_result = true;
    return _ARRAY_SORT_result;
}

IEC_BOOL _BUFFER_CLEAR(IEC_Ptr<BYTE_t> PT, IEC_UINT SIZE) {
    IEC_BOOL _BUFFER_CLEAR_result;
    IEC_Ptr<DWORD_t> PTW;
    IEC_DWORD TEMP;
    IEC_DWORD END;
    IEC_DWORD END32;
    TEMP = PT;
    END = TEMP + TO_DWORD(SIZE);
    END32 = END - 3;
    while ((PT < END) && ((TEMP & 0x00000003) > 0)) {
        (*PT) = 0;
        PT = PT + 1;
        TEMP = TEMP + 1;
    }
    PTW = PT;
    while (PTW < END32) {
        (*PTW) = 0;
        PTW = PTW + 4;
    }
    PT = PTW;
    while (PT < END) {
        (*PT) = 0;
        PT = PT + 1;
    }
    _BUFFER_CLEAR_result = true;
    return _BUFFER_CLEAR_result;
}

IEC_BOOL _BUFFER_INIT(IEC_Ptr<BYTE_t> PT, IEC_UINT SIZE, IEC_BYTE INIT) {
    IEC_BOOL _BUFFER_INIT_result;
    IEC_Ptr<DWORD_t> PTW;
    IEC_DWORD TEMP;
    IEC_DWORD END;
    IEC_DWORD END32;
    TEMP = PT;
    END = TEMP + TO_DWORD(SIZE);
    END32 = END - 3;
    while ((PT < END) && ((TEMP & 0x00000003) > 0)) {
        (*PT) = INIT;
        PT = PT + 1;
        TEMP = TEMP + 1;
    }
    PTW = PT;
    TEMP = SHL(TO_DWORD(INIT), 24) | SHL(TO_DWORD(INIT), 16) | SHL(TO_DWORD(INIT), 8) | TO_DWORD(INIT);
    while (PTW < END32) {
        (*PTW) = TEMP;
        PTW = PTW + 4;
    }
    PT = PTW;
    while (PT < END) {
        (*PT) = INIT;
        PT = PT + 1;
    }
    _BUFFER_INIT_result = true;
    return _BUFFER_INIT_result;
}

IEC_INT _BUFFER_INSERT(IECStringVar<STRING_LENGTH> STR, IEC_INT POS, IEC_Ptr<Array1D<IEC_BYTE, 0, 32767>> PT, IEC_UINT SIZE) {
    IEC_INT _BUFFER_INSERT_result;
    IEC_INT END;
    IEC_INT LX;
    IEC_INT I;
    LX = LEN(STR);
    END = POS + LX;
    for (I = TO_INT(SIZE) - 1; I >= END; I += -1) {
        (*PT)[I] = (*PT)[I - LX];
    }
    _BUFFER_INSERT_result = _STRING_TO_BUFFER(STR, POS, PT, SIZE);
    return _BUFFER_INSERT_result;
}

IEC_BOOL _BUFFER_UPPERCASE(IEC_Ptr<Array1D<IEC_BYTE, 0, 32000>> PT, IEC_INT SIZE) {
    IEC_BOOL _BUFFER_UPPERCASE_result;
    IEC_INT POS;
    POS = 0;
    while (POS < SIZE) {
        (*PT)[POS] = TO_UPPER((*PT)[POS]);
        POS = POS + 1;
    }
    _BUFFER_UPPERCASE_result = true;
    return _BUFFER_UPPERCASE_result;
}

IEC_INT _STRING_TO_BUFFER(IECStringVar<STRING_LENGTH> STR, IEC_INT POS, IEC_Ptr<Array1D<IEC_BYTE, 0, 32767>> PT, IEC_UINT SIZE) {
    IEC_INT _STRING_TO_BUFFER_result;
    IEC_Ptr<BYTE_t> PS;
    IEC_INT I;
    IEC_INT END;
    PS = &(STR);
    END = MIN(POS + LEN(STR), TO_INT(SIZE));
    if (END > 0) {
        END = END - 1;
    }
    for (I = POS; I <= END; I++) {
        (*PT)[I] = (*PS);
        PS = PS + 1;
    }
    _STRING_TO_BUFFER_result = I;
    return _STRING_TO_BUFFER_result;
}


// =============================================================================
// Located Variables Descriptor Array
// =============================================================================

LocatedVar locatedVars[5] = {
    { LocatedArea::Input, LocatedSize::Bit, 0, 0, {0, 0, 0}, nullptr },  // START_BUTTON AT %IX0.0
    { LocatedArea::Input, LocatedSize::Bit, 0, 1, {0, 0, 0}, nullptr },  // STOP_BUTTON AT %IX0.1
    { LocatedArea::Output, LocatedSize::Bit, 0, 0, {0, 0, 0}, nullptr },  // ENABLE_OUTPUT AT %QX0.0
    { LocatedArea::Output, LocatedSize::Word, 2, 0, {0, 0, 0}, nullptr },  // TARGET_WORD AT %QW2
    { LocatedArea::Memory, LocatedSize::Word, 0, 0, {0, 0, 0}, nullptr }  // COUNTER AT %MW0
};

Program_MACHINE::Program_MACHINE()
    : START_BUTTON(false), STOP_BUTTON(false), ENABLE_OUTPUT(false), TARGET_WORD(0), COUNTER(0)
{
    // Initialize located variable pointers
    locatedVars[0].pointer = START_BUTTON.raw_ptr();
    locatedVars[1].pointer = STOP_BUTTON.raw_ptr();
    locatedVars[2].pointer = ENABLE_OUTPUT.raw_ptr();
    locatedVars[3].pointer = TARGET_WORD.raw_ptr();
    locatedVars[4].pointer = COUNTER.raw_ptr();
}

void Program_MACHINE::run() {
    if (STOP_BUTTON) {
        ENABLE_OUTPUT = false;
    } else if (START_BUTTON) {
        ENABLE_OUTPUT = true;
    }
    if (ENABLE_OUTPUT) {
        COUNTER = COUNTER + 1;
        TARGET_WORD = COUNTER;
    } else {
        TARGET_WORD = 0;
    }
}

